import React, { useState, useEffect, useRef } from 'react';
import {
  View, StyleSheet, FlatList, TouchableOpacity, Animated, ScrollView, Dimensions,
} from 'react-native';
import { Text, Chip } from 'react-native-paper';
import { MaterialCommunityIcons as Icon } from '@expo/vector-icons';
import { LinearGradient } from 'expo-linear-gradient';
import AsyncStorage from '@react-native-async-storage/async-storage';

const { width } = Dimensions.get('window');

export default function ProductListScreen({ navigation }) {
  const [searchQuery, setSearchQuery] = useState('');
  const [products, setProducts] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [userType, setUserType] = useState(null);
  const headerAnim = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    loadProducts();
    checkUserType();
    Animated.timing(headerAnim, { toValue: 1, duration: 600, useNativeDriver: true }).start();
  }, []);

  const checkUserType = async () => {
    const type = await AsyncStorage.getItem('userType');
    setUserType(type);
  };

  const loadProducts = async () => {
    try {
      const { getProducts } = require('../services/api');
      const data = await getProducts();
      const gradients = [['#FF6B6B', '#EE5A24'], ['#00C853', '#00E676'], ['#74B9FF', '#0984E3'], ['#FDCB6E', '#F39C12'], ['#A29BFE', '#6C5CE7'], ['#55EFC4', '#00B894']];
      const mappedProducts = data.map((workshop, i) => ({
        id: workshop._id,
        name: workshop.title,
        category: workshop.category,
        price: workshop.fee === 'Free' ? 0 : parseInt(workshop.fee.replace('₹', '')),
        unit: 'session',
        farmer: workshop.trainerName || 'Village Trainer',
        location: `${workshop.district || ''}, ${workshop.state || ''}`,
        stock: workshop.maxParticipants - workshop.enrolledCount,
        image: workshop.image || '🎨',
        rating: workshop.rating || 0,
        organic: workshop.skillLevel === 'Beginner',
        gradient: gradients[i % gradients.length],
      }));
      setProducts(mappedProducts);
    } catch (err) {
      console.error('Error loading workshops:', err);
    }
  };

  const categories = ['All', 'Vegetables', 'Fruits', 'Grains', 'Dairy'];

  const filteredProducts = products.filter((p) => {
    const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase()) || p.farmer.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesCategory = selectedCategory === 'All' || p.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  const renderProduct = ({ item, index }) => {
    return (
      <AnimatedProductCard item={item} index={index} navigation={navigation} userType={userType} />
    );
  };

  return (
    <LinearGradient colors={['#0a1a0f', '#0d2818', '#0a1a0f']} style={styles.container}>
      {/* Header */}
      <Animated.View style={[styles.header, { opacity: headerAnim, transform: [{ translateY: headerAnim.interpolate({ inputRange: [0, 1], outputRange: [-20, 0] }) }] }]}>
        <Text style={styles.headerTitle}>Products</Text>
        <Text style={styles.headerSub}>{filteredProducts.length} items available</Text>
      </Animated.View>

      {/* Search */}
      <View style={styles.searchContainer}>
        <View style={styles.searchWrapper}>
          <Icon name="magnify" size={22} color="rgba(255,255,255,0.4)" />
          <View style={styles.searchInput}>
            <Text
              style={styles.searchPlaceholder}
              onPress={() => {}}
            >
              {searchQuery || 'Search products or farmers...'}
            </Text>
          </View>
        </View>
      </View>

      {/* Category Chips */}
      <View style={styles.categoryContainer}>
        <ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={{ paddingLeft: 20 }}>
          {categories.map((cat) => (
            <TouchableOpacity
              key={cat}
              onPress={() => setSelectedCategory(cat)}
              style={[styles.categoryChip, selectedCategory === cat && styles.categoryChipActive]}
              activeOpacity={0.7}
            >
              <Text style={[styles.categoryChipText, selectedCategory === cat && styles.categoryChipTextActive]}>{cat}</Text>
            </TouchableOpacity>
          ))}
        </ScrollView>
      </View>

      {/* Product List */}
      <FlatList
        data={filteredProducts}
        renderItem={renderProduct}
        keyExtractor={(item) => item.id.toString()}
        contentContainerStyle={styles.listContainer}
        showsVerticalScrollIndicator={false}
        ListEmptyComponent={
          <View style={styles.emptyContainer}>
            <Icon name="package-variant-closed" size={60} color="rgba(255,255,255,0.15)" />
            <Text style={styles.emptyText}>No products found</Text>
          </View>
        }
      />

      {userType === 'farmer' && (
        <TouchableOpacity activeOpacity={0.8} onPress={() => navigation.navigate('AddProduct')}>
          <LinearGradient colors={['#00C853', '#00E676']} style={styles.fab}>
            <Icon name="plus" size={28} color="#0a1a0f" />
          </LinearGradient>
        </TouchableOpacity>
      )}
    </LinearGradient>
  );
}

function AnimatedProductCard({ item, index, navigation, userType }) {
  const anim = useRef(new Animated.Value(0)).current;
  useEffect(() => {
    Animated.spring(anim, { toValue: 1, delay: index * 80, tension: 50, friction: 8, useNativeDriver: true }).start();
  }, []);
  return (
    <Animated.View style={{ opacity: anim, transform: [{ translateY: anim.interpolate({ inputRange: [0, 1], outputRange: [30, 0] }) }] }}>
      <TouchableOpacity style={styles.productCard} activeOpacity={0.8} onPress={() => navigation.navigate('ProductDetail', { product: item })}>
        <View style={styles.productGlass}>
          <View style={styles.productImageWrapper}>
            <LinearGradient colors={item.gradient || ['#00C853', '#00E676']} style={styles.productImgBg}>
              <Text style={styles.productEmoji}>{item.image}</Text>
              {item.organic && (
                <View style={styles.organicBadge}>
                  <Text style={{ fontSize: 10 }}>🌱</Text>
                </View>
              )}
            </LinearGradient>
          </View>
          <View style={styles.productInfo}>
            <Text style={styles.productName} numberOfLines={1}>{item.name}</Text>
            <View style={styles.productMeta}>
              <Icon name="account" size={12} color="rgba(255,255,255,0.4)" />
              <Text style={styles.productMetaText}>{item.farmer}</Text>
            </View>
            <View style={styles.productMeta}>
              <Icon name="map-marker" size={12} color="rgba(255,255,255,0.4)" />
              <Text style={styles.productMetaText}>{item.location}</Text>
            </View>
            <View style={styles.productBottom}>
              <View style={styles.ratingBadge}>
                <Icon name="star" size={11} color="#FFC107" />
                <Text style={styles.ratingText}>{item.rating}</Text>
              </View>
              <Text style={styles.stockText}>Stock: {item.stock}</Text>
            </View>
          </View>
          <View style={styles.priceSection}>
            <Text style={styles.productPrice}>₹{item.price}</Text>
            <Text style={styles.productUnit}>/{item.unit}</Text>
            {userType === 'buyer' && (
              <TouchableOpacity activeOpacity={0.7}>
                <LinearGradient colors={['#00C853', '#00E676']} style={styles.addBtn}>
                  <Icon name="cart-plus" size={18} color="#0a1a0f" />
                </LinearGradient>
              </TouchableOpacity>
            )}
          </View>
        </View>
      </TouchableOpacity>
    </Animated.View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1 },
  header: { paddingHorizontal: 24, paddingTop: 60, paddingBottom: 8 },
  headerTitle: { fontSize: 28, fontWeight: '800', color: '#fff', letterSpacing: -0.5 },
  headerSub: { fontSize: 13, color: 'rgba(255,255,255,0.4)', marginTop: 4 },
  searchContainer: { paddingHorizontal: 20, marginTop: 12, marginBottom: 12 },
  searchWrapper: { flexDirection: 'row', alignItems: 'center', backgroundColor: 'rgba(255,255,255,0.06)', borderRadius: 16, paddingHorizontal: 16, height: 50, borderWidth: 1, borderColor: 'rgba(255,255,255,0.08)' },
  searchInput: { flex: 1, marginLeft: 10 },
  searchPlaceholder: { fontSize: 14, color: 'rgba(255,255,255,0.35)' },
  categoryContainer: { marginBottom: 12 },
  categoryChip: { paddingHorizontal: 18, paddingVertical: 10, borderRadius: 20, marginRight: 10, backgroundColor: 'rgba(255,255,255,0.06)', borderWidth: 1, borderColor: 'rgba(255,255,255,0.08)' },
  categoryChipActive: { backgroundColor: '#00C853', borderColor: '#00C853' },
  categoryChipText: { fontSize: 13, color: 'rgba(255,255,255,0.6)', fontWeight: '600' },
  categoryChipTextActive: { color: '#0a1a0f' },
  listContainer: { paddingBottom: 100 },
  productCard: { paddingHorizontal: 20, marginBottom: 12 },
  productGlass: { flexDirection: 'row', backgroundColor: 'rgba(255,255,255,0.05)', borderRadius: 18, padding: 14, borderWidth: 1, borderColor: 'rgba(255,255,255,0.06)', alignItems: 'center' },
  productImageWrapper: { width: 70, height: 70, borderRadius: 16, overflow: 'hidden' },
